<template>
  <div style="display:flex; align-items:center; justify-content:center; min-height:100vh; background:var(--bg-app);">
    <div class="animate-fade-in" style="text-align:center; max-width:480px; padding:2rem;">
      <div style="width:48px; height:48px; background:var(--accent-primary); border-radius:10px; display:flex; align-items:center; justify-content:center; color:white; font-weight:700; font-size:1.125rem; margin:0 auto 1.5rem;">ES</div>
      <h1 style="font-size:1.75rem; font-weight:700; margin-bottom:0.5rem; letter-spacing:-0.02em;">EventSync</h1>
      <p style="color:var(--text-secondary); font-size:0.9375rem; margin-bottom:2.5rem; line-height:1.6;">
        Système centralisé de gestion du planning, suivi des tâches et évaluation qualité pour les événements Japan Otaku Festival & Japan Manga Wave.
      </p>

      <div style="display:flex; flex-direction:column; gap:0.75rem;">
        <NuxtLink to="/admin" class="btn btn-primary" style="text-decoration:none; padding:0.75rem 1.5rem; font-size:0.9375rem; justify-content:center;">
          Espace Administrateur
        </NuxtLink>
        <button @click="showLogin = true" class="btn btn-secondary" style="width:100%; justify-content:center; padding:0.75rem 1.5rem; font-size:0.9375rem;">
          Espace Employé (Connexion)
        </button>
      </div>

      <p style="color:var(--text-muted); font-size:0.75rem; margin-top:2rem;">v1.0 — Architecture Modulaire Nuxt 3 + PostgreSQL</p>
    </div>

    <!-- Modal Mock Login -->
    <Modal :isOpen="showLogin" title="Connexion Employé" @close="showLogin = false">
      <div style="display:flex; flex-direction:column; gap:1rem;">
        <p style="color:var(--text-secondary); font-size:0.875rem;">Sélectionnez un profil d'employé pour tester l'affichage dynamique :</p>
        <select v-model="selectedEmployeId" class="form-input" style="width:100%;">
          <option value="" disabled>Choisir un profil...</option>
          <option v-for="emp in employes" :key="emp.id" :value="emp.id">
            {{ emp.nom }} {{ emp.prenom }} ({{ emp.poste?.titre_poste || 'Inconnu' }})
          </option>
        </select>
        <div style="display:flex; justify-content:flex-end; gap:0.5rem; margin-top:1rem;">
          <button class="btn btn-secondary" @click="showLogin = false">Annuler</button>
          <button class="btn btn-primary" :disabled="!selectedEmployeId" @click="login">Se connecter</button>
        </div>
      </div>
    </Modal>
  </div>
</template>

<script setup>
import { ref } from 'vue'
import { useRouter } from 'vue-router'

const { data: employes } = await useFetch('/api/equipe')
const showLogin = ref(false)
const selectedEmployeId = ref('')
const router = useRouter()

// On utilise un cookie pour stocker l'ID de l'employé connecté
const loggedEmployeId = useCookie('employe_id')

const login = () => {
  if (selectedEmployeId.value) {
    loggedEmployeId.value = selectedEmployeId.value
    router.push('/employe')
  }
}
</script>
